   166→// ============================================================================
   167→// Saddle - Return context needed to saddle up on a Heat
   168→// ============================================================================
   169→
   170→/// Arguments for saddle command
   171→#[derive(Debug)]
   172→pub struct jjrq_SaddleArgs {
   173→    pub file: std::path::PathBuf,
   174→    pub firemark: Firemark,
   175→}
   176→
   177→/// Output structure for saddle command
   178→#[derive(Serialize)]
   179→pub(crate) struct zjjrq_SaddleOutput {
   180→    pub(crate) heat_silks: String,
   181→    pub(crate) paddock_file: String,
   182→    pub(crate) paddock_content: String,
   183→    #[serde(skip_serializing_if = "Option::is_none")]
   184→    pub(crate) pace_coronet: Option<String>,
   185→    #[serde(skip_serializing_if = "Option::is_none")]
   186→    pub(crate) pace_silks: Option<String>,
   187→    #[serde(skip_serializing_if = "Option::is_none")]
   188→    pub(crate) pace_state: Option<String>,
   189→    #[serde(skip_serializing_if = "Option::is_none")]
   190→    pub(crate) spec: Option<String>,
   191→    #[serde(skip_serializing_if = "Option::is_none")]
   192→    pub(crate) direction: Option<String>,
   193→    pub(crate) recent_work: Vec<jjrs_SteeplechaseEntry>,
   194→}
   195→
   196→/// Run the saddle command - return Heat context
   197→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   198→    let gallops = match Gallops::jjrg_load(&args.file) {
   199→        Ok(g) => g,
   200→        Err(e) => {
   201→            eprintln!("jjx_saddle: error: {}", e);
   202→            return 1;
   203→        }
   204→    };
   205→
   206→    let heat_key = args.firemark.jjrf_display();
   207→    let heat = match gallops.heats.get(&heat_key) {
   208→        Some(h) => h,
   209→        None => {
   210→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   211→            return 1;
   212→        }
   213→    };
   214→
   215→    // Check if heat is stabled (cannot saddle stabled heat)
   216→    if heat.status == HeatStatus::Stabled {
   217→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   218→        return 1;
   219→    }
   220→
   221→    // Read paddock file content
   222→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   223→        Ok(content) => content,
   224→        Err(e) => {
   225→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   226→            return 1;
   227→        }
   228→    };
   229→
   230→    // Get recent steeplechase entries
   231→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   232→        firemark: args.firemark.jjrf_as_str().to_string(),
   233→        limit: 10,
   234→    }).unwrap_or_default();
   235→
   236→    // Find first actionable pace (rough or bridled)
   237→    let mut pace_coronet: Option<String> = None;
   238→    let mut pace_silks: Option<String> = None;
   239→    let mut pace_state: Option<String> = None;
   240→    let mut spec: Option<String> = None;
   241→    let mut direction: Option<String> = None;
   242→
   243→    for coronet_key in &heat.order {
   244→        if let Some(pace) = heat.paces.get(coronet_key) {
   245→            if let Some(tack) = pace.tacks.first() {
   246→                match tack.state {
   247→                    PaceState::Rough | PaceState::Bridled => {
   248→                        pace_coronet = Some(coronet_key.clone());
   249→                        pace_silks = Some(tack.silks.clone());
   250→                        pace_state = Some(match tack.state {
   251→                            PaceState::Rough => "rough".to_string(),
   252→                            PaceState::Bridled => "bridled".to_string(),
   253→                            _ => unreachable!(),
   254→                        });
   255→                        spec = Some(tack.text.clone());
   256→                        if tack.state == PaceState::Bridled {
   257→                            direction = tack.direction.clone();
   258→                        }
   259→                        break;
   260→                    }
   261→                    _ => continue,
   262→                }
   263→            }
   264→        }
   265→    }
   266→
   267→    // Determine heat status string
   268→    let status_str = match heat.status {
   269→        HeatStatus::Racing => "racing",
   270→        HeatStatus::Stabled => "stabled",
   271→        HeatStatus::Retired => "retired",
   272→    };
   273→
   274→    // Output plain text format
   275→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   276→    println!("Paddock: {}", heat.paddock_file);
   277→    println!();
   278→    println!("Paddock-content:");
   279→    for line in paddock_content.lines() {
   280→        println!("  {}", line);
   281→    }
   282→    println!();
   283→
   284→    if let Some(coronet) = pace_coronet {
   285→        if let Some(silks) = pace_silks {
   286→            if let Some(state) = pace_state {
   287→                println!("Next: {} ({}) [{}]", silks, coronet, state);
   288→                println!();
   289→                if let Some(spec_text) = spec {
   290→                    println!("Spec:");
   291→                    for line in spec_text.lines() {
   292→                        println!("  {}", line);
   293→                    }
   294→                    println!();
   295→                }
   296→                if let Some(dir_text) = direction {
   297→                    println!("Direction:");
   298→                    for line in dir_text.lines() {
   299→                        println!("  {}", line);
   300→                    }
   301→                    println!();
   302→                }
   303→            }
   304→        }
   305→    }
   306→
   307→    // Output recent work table
   308→    if !recent_work.is_empty() {
   309→        println!("Recent-work:");
   310→
   311→        let mut table = jjrp_Table::jjrp_new(vec![
   312→            jjrp_Column::new("Timestamp", jjrp_Align::Left),
   313→            jjrp_Column::new("Commit", jjrp_Align::Left),
   314→            jjrp_Column::new("[A]", jjrp_Align::Left),
   315→            jjrp_Column::new("Identity", jjrp_Align::Left),
   316→            jjrp_Column::new("Subject", jjrp_Align::Left),
   317→        ]);
   318→
   319→        // Measure all rows to compute column widths
   320→        for entry in &recent_work {
   321→            let action_str = entry.action.as_ref().map(|a| format!("[{}]", a)).unwrap_or_else(|| "   ".to_string());
   322→            let identity_str = if let Some(ref coronet) = entry.coronet {
   323→                coronet.clone()
   324→            } else {
   325→                heat_key.clone()
   326→            };
   327→            table.jjrp_measure(&[
   328→                &entry.timestamp,
   329→                &entry.commit,
   330→                &action_str,
   331→                &identity_str,
   332→                &entry.subject,
   333→            ]);
   334→        }
   335→
   336→        // Print header and separator
   337→        table.jjrp_print_header();
   338→        table.jjrp_print_separator();
   339→
   340→        // Print data rows
   341→        for entry in &recent_work {
   342→            let action_str = entry.action.as_ref().map(|a| format!("[{}]", a)).unwrap_or_else(|| "   ".to_string());
   343→            let identity_str = if let Some(ref coronet) = entry.coronet {
   344→                coronet.clone()
   345→            } else {
   346→                heat_key.clone()
   347→            };
   348→            table.jjrp_print_row(&[
   349→                &entry.timestamp,
   350→                &entry.commit,
   351→                &action_str,
   352→                &identity_str,
   353→                &entry.subject,
   354→            ]);
   355→        }
   356→    }
   357→
   358→    0
   359→}
