   361→// ============================================================================
   362→// Parade - Display comprehensive Heat status for project review
   363→// ============================================================================
   364→
   365→/// Arguments for parade command
   366→#[derive(Debug)]
   367→pub struct jjrq_ParadeArgs {
   368→    pub file: std::path::PathBuf,
   369→    pub target: String,
   370→    pub full: bool,
   371→    pub remaining: bool,
   372→}
   373→
   374→/// Run the parade command - display comprehensive Heat status
   375→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   376→    let gallops = match Gallops::jjrg_load(&args.file) {
   377→        Ok(g) => g,
   378→        Err(e) => {
   379→            eprintln!("jjx_parade: error: {}", e);
   380→            return 1;
   381→        }
   382→    };
   383→
   384→    // Determine target type by length
   385→    let target_str = args.target.strip_prefix('₢').or_else(|| args.target.strip_prefix('₣')).unwrap_or(&args.target);
   386→
   387→    if target_str.len() == 5 {
   388→        // Coronet - pace view
   389→        let coronet = match Coronet::jjrf_parse(&args.target) {
   390→            Ok(c) => c,
   391→            Err(e) => {
   392→                eprintln!("jjx_parade: error: {}", e);
   393→                return 1;
   394→            }
   395→        };
   396→
   397→        // Extract parent firemark
   398→        let firemark = coronet.jjrf_parent_firemark();
   399→        let heat_key = firemark.jjrf_display();
   400→        let heat = match gallops.heats.get(&heat_key) {
   401→            Some(h) => h,
   402→            None => {
   403→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   404→                return 1;
   405→            }
   406→        };
   407→
   408→        // Find pace
   409→        let coronet_key = coronet.jjrf_display();
   410→        let pace = match heat.paces.get(&coronet_key) {
   411→            Some(p) => p,
   412→            None => {
   413→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
   414→                return 1;
   415→            }
   416→        };
   417→
   418→        // Display tack history - iterate in reverse order (oldest first)
   419→        if !pace.tacks.is_empty() {
   420→            // Print header with current state from tacks[0]
   421→            let current_tack = &pace.tacks[0];
   422→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   423→            println!("Heat: {}", heat_key);
   424→            println!();
   425→
   426→            // Iterate tacks in reverse order (oldest first)
   427→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   428→                let state_str = zjjrq_pace_state_str(&tack.state);
   429→                let commit_str = if tack.commit == "0000000" {
   430→                    "(no commit)".to_string()
   431→                } else {
   432→                    tack.commit.clone()
   433→                };
   434→
   435→                println!("[{}] {} ({})", index, state_str, commit_str);
   436→                println!("    Silks: {}", tack.silks);
   437→                if let Some(ref direction) = tack.direction {
   438→                    println!("    Direction: {}", direction);
   439→                }
   440→                println!();
   441→                // Indent spec text
   442→                for line in tack.text.lines() {
   443→                    println!("    {}", line);
   444→                }
   445→                println!();
   446→            }
   447→        }
   448→    } else if target_str.len() == 2 {
   449→        // Firemark - heat view
   450→        let firemark = match Firemark::jjrf_parse(&args.target) {
   451→            Ok(fm) => fm,
   452→            Err(e) => {
   453→                eprintln!("jjx_parade: error: {}", e);
   454→                return 1;
   455→            }
   456→        };
   457→
   458→        let heat_key = firemark.jjrf_display();
   459→        let heat = match gallops.heats.get(&heat_key) {
   460→            Some(h) => h,
   461→            None => {
   462→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   463→                return 1;
   464→            }
   465→        };
   466→
   467→        if args.full {
   468→            // Full view: paddock + all specs
   469→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   470→                Ok(content) => content,
   471→                Err(e) => {
   472→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   473→                    return 1;
   474→                }
   475→            };
   476→
   477→            let status_str = match heat.status {
   478→                HeatStatus::Racing => "racing",
   479→                HeatStatus::Stabled => "stabled",
   480→                HeatStatus::Retired => "retired",
   481→            };
   482→
   483→            println!("Heat: {} ({})", heat.silks, heat_key);
   484→            println!("Status: {}", status_str);
   485→            println!("Created: {}", heat.creation_time);
   486→            println!();
   487→            println!("## Paddock");
   488→            println!();
   489→            println!("{}", paddock_content);
   490→            println!();
   491→            println!("## Paces");
   492→            println!();
   493→
   494→            for coronet_key in &heat.order {
   495→                if let Some(pace) = heat.paces.get(coronet_key) {
   496→                    if let Some(tack) = pace.tacks.first() {
   497→                        // Skip complete/abandoned if --remaining
   498→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   499→                            continue;
   500→                        }
   501→                        let state_str = zjjrq_pace_state_str(&tack.state);
   502→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   503→                        println!();
   504→                        println!("{}", tack.text);
   505→                        if let Some(ref direction) = tack.direction {
   506→                            println!();
   507→                            println!("**Direction:** {}", direction);
   508→                        }
   509→                        println!();
   510→                    }
   511→                }
   512→            }
   513→        } else {
   514→            // List view: numbered paces
   515→            // If --remaining, output markdown format
   516→            if args.remaining {
   517→                let mut complete_count = 0;
   518→                let mut abandoned_count = 0;
   519→                let mut rough_count = 0;
   520→                let mut bridled_count = 0;
   521→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
   522→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
   523→
   524→                for coronet_key in &heat.order {
   525→                    if let Some(pace) = heat.paces.get(coronet_key) {
   526→                        if let Some(tack) = pace.tacks.first() {
   527→                            match tack.state {
   528→                                PaceState::Complete => complete_count += 1,
   529→                                PaceState::Abandoned => abandoned_count += 1,
   530→                                PaceState::Rough => {
   531→                                    rough_count += 1;
   532→                                    remaining_paces.push((coronet_key, pace));
   533→                                    if first_remaining_pace.is_none() {
   534→                                        first_remaining_pace = Some((coronet_key, pace));
   535→                                    }
   536→                                }
   537→                                PaceState::Bridled => {
   538→                                    bridled_count += 1;
   539→                                    remaining_paces.push((coronet_key, pace));
   540→                                    if first_remaining_pace.is_none() {
   541→                                        first_remaining_pace = Some((coronet_key, pace));
   542→                                    }
   543→                                }
   544→                            }
   545→                        }
   546→                    }
   547→                }
   548→
   549→                let status_str = match heat.status {
   550→                    HeatStatus::Racing => "racing",
   551→                    HeatStatus::Stabled => "stabled",
   552→                    HeatStatus::Retired => "retired",
   553→                };
   554→
   555→                let remaining_count = rough_count + bridled_count;
   556→
   557→                // Header line with heat info
   558→                println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   559→                println!("Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
   560→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
   561→                println!();
   562→
   563→                // Table with remaining paces
   564→                if !remaining_paces.is_empty() {
   565→                    // Set up table with column definitions
   566→                    let mut table = jjrp_Table::jjrp_new(vec![
   567→                        jjrp_Column::new("No", jjrp_Align::Right),
   568→                        jjrp_Column::new("State", jjrp_Align::Left),
   569→                        jjrp_Column::new("Pace", jjrp_Align::Left),
   570→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   571→                    ]);
   572→
   573→                    // Measure all rows to compute column widths
   574→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
